using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.ApiTests;/// <summary>/// Bad case: Try to access EHR document with invalid requester ID format/// Expected: 400 Bad Request or 404 Not Found/// </summary>public class EhrServiceTests_GetEhrDocument_WithInvalidRequesterId_ShouldReturnError : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "EhrService"    };    [SkippableFact]    public async Task GetEhrDocument_WithInvalidRequesterId_ShouldReturnError()    {        await AuthenticateAsDoctorAsync(EhrClient);        var ehrId = Guid.NewGuid();                // Create request with invalid requester ID (non-existent user)        var request = EhrClient.CreateRequest(HttpMethod.Get, ApiEndpoints.Ehr.GetDocument(ehrId));        request.Headers.Add("X-Requester-Id", Guid.NewGuid().ToString());        var response = await EhrClient.SendAsync(request);        // Should return 404, 403, or handle gracefully        Assert.True(            response.StatusCode == HttpStatusCode.NotFound ||             response.StatusCode == HttpStatusCode.Forbidden ||            response.StatusCode == HttpStatusCode.BadRequest,            $"Expected 404, 403, or 400, got {response.StatusCode}");    }}
